const cfg = $items('Detectar Ambiente Automático')[0].json;
const baseUrl = cfg.python_worker_url;
const maxAttempts = 720; // 720 * 10s = 2 horas máximo
const delayMs = 10000; // 10 segundos entre checagens

function delay(ms) { return new Promise(resolve => setTimeout(resolve, ms)); }

async function getStatus() {
  return await this.helpers.httpRequest({
    method: 'GET',
    url: `${baseUrl}/status`,
    json: true
  });
}

let finalStatus = null;

for (let i = 0; i < maxAttempts; i++) {
  try {
    const res = await getStatus.call(this);
    if (res.status === 'done' || res.status === 'error') {
      finalStatus = res;
      break;
    }
  } catch (err) {
    // ignora erro de rede temporário
  }
  await delay(delayMs);
}

if (!finalStatus) throw new Error('Timeout esperando o Python Worker');
if (finalStatus.status === 'error') throw new Error(`Erro no Python Worker: ${finalStatus.message}`);

return [{ json: { status: 'SUCESSO', worker_response: finalStatus } }];

const cfg = $items('Detectar Ambiente Automático')[0].json;
const payload = $input.first().json;

const records = payload.records || [];
const sqlLines = [];

function escSql(s='') { return String(s || '').replace(/'/g, "''"); }

for (const r of records) {
  const cnpj = r.cnpj_fundo;
  if (!cnpj) continue;

  if (cfg.procedures.razaoSocial && r.razao_social_final) {
    sqlLines.push(`${cfg.procedures.razaoSocial}('${cnpj}','${escSql(r.razao_social_normalizada || r.razao_social_final)}');`);
  }
  if (cfg.procedures.administrador && r.administrador_id && r.administrador_nome) {
    sqlLines.push(`${cfg.procedures.administrador}('${cnpj}','${r.administrador_id}','${escSql(r.administrador_nome)}');`);
  }
  if (cfg.procedures.gestor && r.gestor_id && r.gestor_nome) {
    sqlLines.push(`${cfg.procedures.gestor}('${cnpj}','${r.gestor_id}','${escSql(r.gestor_nome)}');`);
  }
  if (cfg.procedures.escriturador && r.escriturador_id && r.escriturador_nome) {
    sqlLines.push(`${cfg.procedures.escriturador}('${cnpj}','${r.escriturador_id}','${escSql(r.escriturador_nome)}');`);
  }
  if (cfg.procedures.naturezaEconomica && r.natureza_economica_final) {
    sqlLines.push(`${cfg.procedures.naturezaEconomica}('${cnpj}','${escSql(r.natureza_economica_final)}');`);
  }
  if (cfg.procedures.naturezaJuridica && r.natureza_juridica_final) {
    sqlLines.push(`${cfg.procedures.naturezaJuridica}('${cnpj}','${escSql(r.natureza_juridica_final)}');`);
  }
  if (cfg.procedures.tipoFundo && r.tipo_fundo) {
    sqlLines.push(`${cfg.procedures.tipoFundo}('${cnpj}','${escSql(r.tipo_fundo)}');`);
  }
  if (cfg.procedures.denominacaoSocialFundo && r.denominacao_social_fundo) {
    sqlLines.push(`${cfg.procedures.denominacaoSocialFundo}('${cnpj}','${escSql(r.denominacao_social_fundo)}');`);
  }
  if (cfg.procedures.denominacaoSocialClasse && r.denominacao_social_classe) {
    sqlLines.push(`${cfg.procedures.denominacaoSocialClasse}('${cnpj}','${escSql(r.denominacao_social_classe)}');`);
  }
}

const finalSql = sqlLines.join('\n');

return [{
  json: { 
    status: 'SUCESSO',
    total_registros: records.length,
    total_querys: sqlLines.length
  },
  binary: {
    data: {
      data: Buffer.from(finalSql, 'utf-8').toString('base64'),
      mimeType: 'application/sql',
      fileName: cfg.sql_output_path
    }
  }
}];
